"""StreamManager — Generator 팬아웃, 버퍼링, 리플레이."""

from __future__ import annotations

import inspect
from typing import Any, Generator, Iterator


class BufferedFactory:
    """Generator를 소비하면서 버퍼에 저장. 독립 리플레이 생성."""

    def __init__(self, chunks: list[Any]):
        self._chunks = chunks

    def create_generator(self) -> Generator:
        yield from self._chunks

    @property
    def chunks(self) -> list[Any]:
        return self._chunks


class StreamManager:
    """Generator 팬아웃, 버퍼링, 리플레이를 관리."""

    def __init__(self):
        self._buffers: list[BufferedFactory] = []

    def is_generator(self, value: Any) -> bool:
        return (
            inspect.isgenerator(value)
            or (hasattr(value, "__iter__") and hasattr(value, "__next__")
                and not isinstance(value, (str, bytes, dict, list)))
        )

    def buffer(self, gen: Generator | Iterator) -> BufferedFactory:
        """Generator를 소비하면서 버퍼에 저장."""
        chunks = list(gen)
        factory = BufferedFactory(chunks)
        self._buffers.append(factory)
        return factory

    def fan_out(self, value: Any, consumer_count: int) -> list[Any]:
        """값을 consumer_count개로 복제.

        Generator/Iterator면 buffer → create_generator() × N.
        일반 값이면 그대로 N번 반환.
        """
        if consumer_count <= 0:
            return []

        if self.is_generator(value):
            factory = self.buffer(value)
            return [factory.create_generator() for _ in range(consumer_count)]

        if isinstance(value, BufferedFactory):
            return [value.create_generator() for _ in range(consumer_count)]

        return [value] * consumer_count

    def cleanup(self) -> None:
        self._buffers.clear()
